tool_returns.detail:
{
  "tools": [
    {
      "name": "create_subscription",
      "description": "Create a subscription with billing details (deeply nested).",
      "parameters": {
        "type": "object",
        "properties": {
          "user": {
            "type": "object",
            "properties": {
              "id": { "type": "string", "minLength": 1 },
              "contact": {
                "type": "object",
                "properties": {
                  "email": { "type": "string", "format": "email" },
                  "address": {
                    "type": "object",
                    "properties": {
                      "country": { "type": "string", "minLength": 2 },
                      "city":    { "type": "string", "minLength": 1 }
                    },
                    "required": ["country", "city"],
                    "additionalProperties": false
                  }
                },
                "required": ["email", "address"],
                "additionalProperties": false
              }
            },
            "required": ["id", "contact"],
            "additionalProperties": false
          },
          "plan": { "type": "string", "enum": ["basic", "pro", "enterprise"] }
        },
        "required": ["user", "plan"],
        "additionalProperties": false
      }
    }
  ]
}

model_output:
